$ErrorActionPreference = 'Stop'; $pidFile = Join-Path (Join-Path (Split-Path -Parent $PSScriptRoot) '.demo-runtime') 'pids.json'; if (-not (Test-Path $pidFile)) { Write-Host 'No demo PID file found.'; exit 0 }; (Get-Content -Raw $pidFile | ConvertFrom-Json).psobject.Properties.Value | ForEach-Object { Stop-Process -Id $_ -Force -ErrorAction SilentlyContinue }; Remove-Item $pidFile -Force
